mapper.select:
SELECT o.id, o.order_no AS orderNo, o.member_id AS memberId, COALESCE(NULLIF(TRIM(m.name), ''), NULLIF(TRIM(o.customer_name), '')) AS memberName, o.user_id AS userId, u.real_name AS userName, o.total_amount AS totalAmount, o.discount_amount AS discountAmount, o.real_amount AS realAmount, o.pay_type AS payType, o.status, o.remark, o.customer_name AS customerName, o.customer_phone AS customerPhone, o.repay_date AS repayDate, o.delivery_date AS deliveryDate, o.customer_address AS customerAddress, o.customer_gender AS customerGender, o.order_date AS orderDate, o.paid_time AS paidTime, o.create_time AS createTime FROM sale_order o LEFT JOIN sys_user u ON o.user_id = u.id LEFT JOIN member m ON o.member_id = m.id WHERE o.deleted = 0
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.pay_type = #{payType}
AND o.status = #{status}
AND DATE(o.create_time) >= #{startDate}
AND DATE(o.create_time) <= #{endDate}
AND o.member_id = #{memberId}
ORDER BY o.create_time DESC
